#!/usr/bin/env node
/**
 * COMMIT MESSAGE GUARD — HAEMI LIFE ENTERPRISE GIT GOVERNANCE
 *
 * Enforces Conventional Commit standard on all commits.
 * See: https://www.conventionalcommits.org/en/v1.0.0/
 *
 * Allowed format: type(scope): description
 * Allowed types: feat, fix, refactor, test, chore, docs, style, perf, ci, build, revert
 *
 * Usage: node scripts/commit-msg-guard.js <path-to-commit-msg-file>
 */

'use strict';

const fs = require('fs');

// ─── Configuration ────────────────────────────────────────────────────────────

const ALLOWED_TYPES = [
  'feat',
  'fix',
  'refactor',
  'test',
  'chore',
  'docs',
  'style',
  'perf',
  'ci',
  'build',
  'revert',
];

// Conventional Commit format: type(scope): description  OR  type: description
// Scope is optional but recommended for healthcare engineering discipline
const CONVENTIONAL_COMMIT_REGEX =
  /^(feat|fix|refactor|test|chore|docs|style|perf|ci|build|revert)(\([a-z0-9\-\/]+\))?: .{10,}/;

// Patterns to skip (auto-generated by Git tooling)
const SKIP_PATTERNS = [
  /^Merge/,           // Catches "Merge <hash>", "Merge branch", "Merge pull request", etc.
  /^Revert "/,
  /^Initial commit/i,
];

// ─── Main ─────────────────────────────────────────────────────────────────────

function main() {
  const commitMsgFile = process.argv[2];

  if (!commitMsgFile) {
    console.error('❌ Commit-msg guard: No commit message file provided.');
    console.error('   Usage: node scripts/commit-msg-guard.js <path-to-commit-msg-file>');
    process.exit(1);
  }

  let commitMsg;
  try {
    // Read as Buffer first to allow BOM stripping.
    // Windows tools (PowerShell Out-File, Git on Windows) may write a
    // UTF-8 BOM (0xEF 0xBB 0xBF) which would corrupt the regex match.
    const raw = fs.readFileSync(commitMsgFile);
    const bom = Buffer.from([0xef, 0xbb, 0xbf]);
    const content = raw.slice(0, 3).equals(bom) ? raw.slice(3) : raw;
    commitMsg = content.toString('utf8').trim();
  } catch {
    console.error(`❌ Commit-msg guard: Cannot read commit message file: ${commitMsgFile}`);
    process.exit(1);
  }

  // Strip comment lines (lines starting with #)
  const messageLines = commitMsg.split('\n').filter((line) => !line.startsWith('#'));
  const firstLine = messageLines[0]?.trim() || '';

  console.log(`\n🔍 Haemi CI — Commit Message Validation`);
  console.log(`   Message: "${firstLine}"`);
  console.log(`─────────────────────────────────────────────────────────`);

  // Skip auto-generated Git commit messages
  for (const pattern of SKIP_PATTERNS) {
    if (pattern.test(firstLine)) {
      console.log(`✅ Auto-generated commit message detected — skipping validation.`);
      process.exit(0);
    }
  }

  // Validate against Conventional Commit format
  if (!CONVENTIONAL_COMMIT_REGEX.test(firstLine)) {
    console.error(`\n🚨 COMMIT BLOCKED — Commit message does not follow Conventional Commit format.`);
    console.error(`─────────────────────────────────────────────────────────`);
    console.error(`Your message:  "${firstLine}"`);
    console.error(`\nRequired format:`);
    console.error(`  type(scope): description (minimum 10 characters)`);
    console.error(`\nAllowed types:`);
    console.error(`  ${ALLOWED_TYPES.join(', ')}`);
    console.error(`\nExamples:`);
    console.error(`  feat(auth): implement refresh token rotation security`);
    console.error(`  fix(ci): resolve backend test environment variables`);
    console.error(`  refactor(auth): simplify session validation logic`);
    console.error(`  chore(deps): upgrade express to 4.18.3`);
    console.error(`  docs(api): update authentication endpoint documentation`);
    console.error(`─────────────────────────────────────────────────────────\n`);
    process.exit(1);
  }

  console.log(`✅ Commit message passes Conventional Commit validation.\n`);
  process.exit(0);
}

main();
